# main.py# === Import your project modules ===from loaders.raman_loader import select_directory, select_file, load_ramanfrom preprocessors.raman_preprocess import preprocess_pipeline_1, preprocess_pipeline_2, group_preprocess, group_preprocess_2, avg_y_blockfrom preprocessors.aligner import align_xy, align_group_xyimport osimport pandas as pdfrom models.run_loops import run_regression_loop, run_classification_loop# === Step 1: Select Raw Data Directory ===print("\n📂 Select the directory containing your raw Raman .spc files:")directory = select_directory()# === Step 2: Set up Output Directories ===spectra_dir = os.path.join(directory, "Raman_Spectra")results_dir = os.path.join(directory, "Model_Results")os.makedirs(spectra_dir, exist_ok=True)os.makedirs(results_dir, exist_ok=True)# === Step 3: Load Raw Raman Spectra ===sample_spectra, shifts, sample_groups = load_raman(directory, spectra_dir)# === Step 4: Preprocess Spectra ===preprocessed_sample_spectra, cropped_axis = preprocess_pipeline_2(sample_spectra, spectra_dir)#preprocessed_group_spectra, cropped_axis = group_preprocess_2(sample_spectra, sample_groups, spectra_dir)# === Step 5: Load Target Table (GCMS or Metadata) ===print("\n📄 Select the GCMS or Target Excel file:")gcms_path = select_file()gcms_df = pd.read_excel(gcms_path)gcms_df.set_index('ID', inplace=True)gcms_group_df = avg_y_block(gcms_df)# === Step 6: Align X and Y ===filtered_X, filtered_Y, filtered_sample_ids, filtered_groups = align_xy(preprocessed_sample_spectra, gcms_df)#filtered_X, filtered_Y, filtered_sample_ids, filtered_groups = align_group_xy(preprocessed_group_spectra, gcms_group_df)# === Step 7: Modeling Loops ===run_regression_loop(filtered_X, filtered_Y, results_dir, cropped_axis, groups=None)#run_classification_loop(filtered_X, filtered_Y, results_dir, cropped_axis, groups=filtered_groups)